import React, { useState } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { useNotif, NOTIF_TYPES } from '../../contexts/NotifContext';
import { Ic } from '../../components/common/Icons';
import { useApp, fmt } from '../../contexts/AppContext';
import { useI18n } from '../../contexts/i18nContext';


//  Design tokens 
const TEAL    = '#166a52';
const TEAL_DK = '#0d4a39';
const ROLES = {
  producer:    { color: '#b87333', bg: 'rgba(184,115,51,0.10)', label: 'Producer',    icon: <Ic name="mine" size={12}/>,   iconName: 'mine'   },
  regulator:   { color: '#1a5fa0', bg: 'rgba(26,95,160,0.10)',  label: 'Regulator',   icon: <Ic name="shield" size={12}/>, iconName: 'scale'  },
  transporter: { color: '#166a52', bg: 'rgba(22,106,82,0.10)',  label: 'Transporter', icon: <Ic name="truck" size={12}/>,  iconName: 'truck'  },
  admin:       { color: '#6d3fa0', bg: 'rgba(109,63,160,0.10)', label: 'Admin',       icon: <Ic name="shield" size={12}/>, iconName: 'shield' },
};
const STATUS = {
  approved: { color: '#166a52', bg: 'rgba(22,106,82,0.10)', label: 'Approved' },
  pending:  { color: '#b45309', bg: 'rgba(180,83,9,0.10)',  label: 'Pending'  },
  rejected: { color: '#c0392b', bg: 'rgba(192,57,43,0.10)', label: 'Rejected' },
};

//  Small reusable pill 
function Pill({ color, bg, children }) {
  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center', gap: 4,
      padding: '2px 9px', borderRadius: 99,
      background: bg, color, fontSize: '0.68rem', fontWeight: 700,
      letterSpacing: '0.04em', whiteSpace: 'nowrap',
      border: `1px solid ${color}30`,
    }}>
      {children}
    </span>
  );
}

//  Stat card 
function Stat({ label, value, icon, color }) {
  return (
    <div style={{
      background: 'var(--bg-raised)', borderRadius: 'var(--r-md)',
      padding: '16px 20px', border: '1px solid var(--border-soft)',
      boxShadow: 'var(--shadow-xs)',
    }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 10 }}>
        <div style={{ width: 34, height: 34, borderRadius: 8, background: `${color}18`, border: `1px solid ${color}30`, display: 'flex', alignItems: 'center', justifyContent: 'center', color }}>
          {icon}
        </div>
        <span style={{ fontSize: '0.68rem', color: 'var(--text-muted)', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.08em' }}>
          {label}
        </span>
      </div>
      <div style={{ fontSize: '1.9rem', fontWeight: 700, color: 'var(--text-primary)', fontFamily: 'var(--font-display)', lineHeight: 1 }}>
        {value}
      </div>
    </div>
  );
}

//  Section header 
function SectionHead({ icon, title, count }) {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 16 }}>
      <div style={{ width: 32, height: 32, borderRadius: 8, background: 'var(--brand-dim)', color: 'var(--brand)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        {icon}
      </div>
      <h2 style={{ fontSize: '1rem', fontWeight: 700, color: 'var(--text-primary)', margin: 0, fontFamily: 'var(--font-display)' }}>
        {title}
      </h2>
      {count != null && (
        <span style={{ marginLeft: 4, padding: '1px 8px', borderRadius: 99, background: 'var(--brand-dim)', color: 'var(--brand)', fontSize: '0.72rem', fontWeight: 700 }}>
          {count}
        </span>
      )}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
//  USERS MANAGEMENT TAB
// ════════════════════════════════════════════════════════════════════════════
function UsersTab() {
  const { currentUser, users, approveUser, rejectUser, revokeUser } = useAuth();
  const { notify } = useNotif();
  const [tab,    setTab]    = useState('pending');
  const [search, setSearch] = useState('');
  const [rejectId,     setRejectId]     = useState(null);
  const [rejectReason, setRejectReason] = useState('');
  const [deleteId,     setDeleteId]     = useState(null);

  // deleteUser — simple removal from localStorage
  const handleDelete = (userId) => {
    const allUsers = JSON.parse(localStorage.getItem('mc_users') || '[]');
    const updated  = allUsers.filter(u => u.id !== userId);
    localStorage.setItem('mc_users', JSON.stringify(updated));
    window.location.reload(); // force refresh
  };

  const filtered = users.filter(u => {
    if (u.id === currentUser?.id) return false;
    if (tab === 'pending'  && u.account_status !== 'pending')  return false;
    if (tab === 'approved' && u.account_status !== 'approved') return false;
    if (tab === 'rejected' && u.account_status !== 'rejected') return false;
    if (search && ![u.full_name, u.username, u.email, u.organization]
        .join(' ').toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });

  const counts = {
    pending:  users.filter(u => u.account_status === 'pending'  && u.id !== currentUser?.id).length,
    approved: users.filter(u => u.account_status === 'approved' && u.id !== currentUser?.id).length,
    rejected: users.filter(u => u.account_status === 'rejected').length,
  };

  const TABS = [
    { id: 'pending',  label: 'Pending',  count: counts.pending  },
    { id: 'approved', label: 'Approved', count: counts.approved },
    { id: 'rejected', label: 'Rejected', count: counts.rejected },
    { id: 'all',      label: 'All',      count: users.filter(u => u.id !== currentUser?.id).length },
  ];

  return (
    <div>
      {/* Stats */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 12, marginBottom: 24 }}>
        <Stat label="Pending"  value={counts.pending}  icon={<Ic name="clock" size={16}/>}  color="#b45309"/>
        <Stat label="Approved" value={counts.approved} icon={<Ic name="check" size={16}/>}  color={TEAL}/>
        <Stat label="Rejected" value={counts.rejected} icon={<Ic name="x" size={16}/>}      color="#c0392b"/>
        <Stat label="Total"    value={users.filter(u => u.id !== currentUser?.id).length} icon={<Ic name="users" size={16}/>} color="#6d3fa0"/>
      </div>

      {/* Alert banner */}
      {counts.pending > 0 && (
        <div style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '10px 16px', marginBottom: 16, background: 'rgba(180,83,9,0.08)', border: '1px solid rgba(245,158,11,0.25)', borderRadius: 'var(--r-md)', cursor: 'pointer' }}
          onClick={() => setTab('pending')}>
          <Ic name="clock" size={16} />
          <span style={{ fontSize: '0.85rem', color: '#b45309', fontWeight: 600 }}>
            {counts.pending} account{counts.pending > 1 ? 's' : ''} awaiting approval
          </span>
          <span style={{ marginLeft: 'auto', fontSize: '0.78rem', color: '#b45309', textDecoration: 'underline' }}>Review →</span>
        </div>
      )}

      {/* Tabs + search */}
      <div style={{ display: 'flex', gap: 10, marginBottom: 18, flexWrap: 'wrap', alignItems: 'center' }}>
        <div style={{ display: 'flex', gap: 0, background: 'var(--bg-void)', borderRadius: 'var(--r-sm)', padding: 3, border: '1px solid var(--border-soft)' }}>
          {TABS.map(t => (
            <button key={t.id} onClick={() => setTab(t.id)} style={{
              padding: '6px 14px', borderRadius: 6, border: 'none', cursor: 'pointer',
              background: tab === t.id ? 'var(--brand)' : 'transparent',
              color: tab === t.id ? '#fff' : 'var(--text-muted)',
              fontWeight: tab === t.id ? 700 : 500, fontSize: '0.8rem',
              fontFamily: 'var(--font-body)', display: 'flex', alignItems: 'center', gap: 6,
            }}>
              {t.label}
              {t.count > 0 && (
                <span style={{ background: tab === t.id ? 'rgba(255,255,255,0.25)' : 'var(--brand-dim)', color: tab === t.id ? '#fff' : 'var(--brand)', borderRadius: 99, padding: '0 6px', fontSize: '0.68rem', fontWeight: 700 }}>
                  {t.count}
                </span>
              )}
            </button>
          ))}
        </div>
        <div style={{ position: 'relative', flex: 1, maxWidth: 280 }}>
          <input className="form-input" placeholder="Search users…" value={search}
            onChange={e => setSearch(e.target.value)}
            style={{ paddingLeft: 34 }}/>
          <span style={{ position: 'absolute', left: 10, top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }}>
            <Ic size={14} d={<><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></>}/>
          </span>
        </div>
      </div>

      {/* User list */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
        {filtered.length === 0 ? (
          <div style={{ padding: '40px 24px', textAlign: 'center', background: 'var(--bg-raised)', borderRadius: 'var(--r-lg)', border: '1px solid var(--border-soft)' }}>
            <div style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>No users found</div>
          </div>
        ) : filtered.map(user => {
          const role   = ROLES[user.role]  || ROLES.admin;
          const status = STATUS[user.account_status] || STATUS.pending;
          const isDemo = user.id.startsWith('demo-');

          return (
            <div key={user.id} style={{
              background: 'var(--bg-raised)', borderRadius: 'var(--r-md)',
              border: `1px solid ${user.account_status === 'pending' ? 'rgba(245,158,11,0.3)' : 'var(--border-soft)'}`,
              padding: '16px 18px',
              boxShadow: user.account_status === 'pending' ? '0 0 0 3px rgba(245,158,11,0.06)' : 'var(--shadow-xs)',
            }}>
              <div style={{ display: 'flex', alignItems: 'flex-start', gap: 14 }}>
                {/* Avatar */}
                <div style={{
                  width: 40, height: 40, borderRadius: '50%', flexShrink: 0,
                  background: role.bg, border: `2px solid ${role.color}30`,
                  display: 'flex', alignItems: 'center', justifyContent: 'center', color: role.color,
                }}>
                  {React.cloneElement(role.icon, { s: 16 })}
                </div>

                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 4, flexWrap: 'wrap' }}>
                    <span style={{ fontWeight: 700, fontSize: '0.92rem', color: 'var(--text-primary)' }}>
                      {user.full_name}
                    </span>
                    <Pill color={role.color} bg={role.bg}>{role.label}</Pill>
                    <Pill color={status.color} bg={status.bg}>{status.label}</Pill>
                    {isDemo && <Pill color="var(--text-muted)" bg="var(--bg-hover)">demo</Pill>}
                  </div>
                  <div style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', marginBottom: 4 }}>
                    @{user.username} · {user.email}
                  </div>
                  <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', display: 'flex', gap: 16, flexWrap: 'wrap' }}>
                    {user.organization && <span>{user.organization}</span>}
                    {user.site && <span>Site: {user.site}</span>}
                    <span>Registered: {fmt.date(user.created_at)}</span>
                    {user.approved_at && <span>Processed: {fmt.date(user.approved_at)}</span>}
                  </div>
                  {/* Permissions */}
                  <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap', marginTop: 8 }}>
                    {(user.permissions || []).map(p => (
                      <span key={p} style={{ fontSize: '0.62rem', padding: '2px 7px', background: 'var(--bg-void)', border: '1px solid var(--border-soft)', borderRadius: 99, color: 'var(--text-muted)' }}>
                        {p.replace(/_/g, ' ')}
                      </span>
                    ))}
                  </div>
                  {user.registration_note && (
                    <div style={{ marginTop: 8, padding: '7px 11px', background: 'var(--bg-void)', borderRadius: 8, fontSize: '0.76rem', color: 'var(--text-secondary)', fontStyle: 'italic', borderLeft: '3px solid var(--border-medium)' }}>
                      "{user.registration_note}"
                    </div>
                  )}
                  {user.rejection_reason && (
                    <div style={{ marginTop: 8, padding: '6px 10px', background: 'var(--crimson-dim)', border: '1px solid var(--crimson)30', borderRadius: 8, fontSize: '0.73rem', color: 'var(--crimson)' }}>
                      Rejection reason: {user.rejection_reason}
                    </div>
                  )}
                </div>

                {/* Actions */}
                {!isDemo && (
                  <div style={{ display: 'flex', gap: 6, flexShrink: 0 }}>
                    {user.account_status === 'pending' && (
                      <>
                        <button onClick={() => { approveUser(user.id, currentUser.id); notify(NOTIF_TYPES.USER_APPROVED, { userName: user.full_name, role: user.role }); }}
                          title="Approve" style={{ padding: '7px 12px', borderRadius: 'var(--r-sm)', border: '1px solid rgba(22,106,82,0.3)', background: 'rgba(22,106,82,0.08)', color: TEAL, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 5, fontSize: '0.78rem', fontWeight: 600, fontFamily: 'var(--font-body)' }}>
                          <Ic name="check" size={13}/> Approve
                        </button>
                        <button onClick={() => setRejectId(user.id)}
                          title="Reject" style={{ padding: '7px 12px', borderRadius: 'var(--r-sm)', border: '1px solid rgba(192,57,43,0.25)', background: 'rgba(192,57,43,0.07)', color: 'var(--crimson)', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 5, fontSize: '0.78rem', fontWeight: 600, fontFamily: 'var(--font-body)' }}>
                          <Ic name="x" size={13}/> Reject
                        </button>
                      </>
                    )}
                    {user.account_status === 'approved' && (
                      <button onClick={() => revokeUser(user.id, currentUser.id)}
                        title="Revoke access" style={{ padding: '7px 12px', borderRadius: 'var(--r-sm)', border: '1px solid var(--border-soft)', background: 'transparent', color: 'var(--text-muted)', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 5, fontSize: '0.75rem', fontFamily: 'var(--font-body)' }}>
                        <Ic name="history" size={13}/> Revoke
                      </button>
                    )}
                    <button onClick={() => setDeleteId(user.id)}
                      title="Delete account" style={{ padding: '7px 10px', borderRadius: 'var(--r-sm)', border: '1px solid rgba(192,57,43,0.2)', background: 'transparent', color: 'var(--crimson)', cursor: 'pointer' }}>
                      <Ic name="trash" size={14}/>
                    </button>
                  </div>
                )}
              </div>

              {/* Reject reason form */}
              {rejectId === user.id && (
                <div style={{ borderTop: '1px solid var(--border-dim)', marginTop: 12, paddingTop: 12 }}>
                  <input className="form-input" placeholder="Rejection reason (required)…"
                    value={rejectReason} onChange={e => setRejectReason(e.target.value)}
                    style={{ marginBottom: 8 }}/>
                  <div style={{ display: 'flex', gap: 8 }}>
                    <button disabled={!rejectReason.trim()} onClick={() => { rejectUser(user.id, currentUser.id, rejectReason); setRejectId(null); setRejectReason(''); }}
                      style={{ padding: '7px 16px', borderRadius: 'var(--r-sm)', background: 'var(--crimson)', color: '#fff', border: 'none', cursor: 'pointer', fontSize: '0.8rem', fontWeight: 600, fontFamily: 'var(--font-body)', opacity: rejectReason.trim() ? 1 : 0.5 }}>
                      Confirm rejection
                    </button>
                    <button onClick={() => { setRejectId(null); setRejectReason(''); }}
                      style={{ padding: '7px 14px', borderRadius: 'var(--r-sm)', background: 'transparent', border: '1px solid var(--border-soft)', color: 'var(--text-muted)', cursor: 'pointer', fontSize: '0.8rem', fontFamily: 'var(--font-body)' }}>
                      Cancel
                    </button>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Delete confirmation modal */}
      {deleteId && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <div style={{ background: 'var(--bg-surface)', borderRadius: 'var(--r-xl)', padding: '28px 32px', maxWidth: 380, width: '90%', boxShadow: 'var(--shadow-xl)', border: '1px solid var(--border-soft)' }}>
            <div style={{ width: 44, height: 44, borderRadius: '50%', background: 'var(--crimson-dim)', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 14px', color: 'var(--crimson)' }}>
              <Ic name="trash" size={20}/>
            </div>
            <h3 style={{ textAlign: 'center', fontFamily: 'var(--font-display)', fontSize: '1.1rem', marginBottom: 8, color: 'var(--text-primary)' }}>Delete Account</h3>
            <p style={{ textAlign: 'center', fontSize: '0.85rem', color: 'var(--text-secondary)', lineHeight: 1.6, marginBottom: 20 }}>
              This action is permanent and cannot be undone.
            </p>
            <div style={{ display: 'flex', gap: 10 }}>
              <button onClick={() => setDeleteId(null)}
                style={{ flex: 1, padding: '10px', borderRadius: 'var(--r-md)', border: '1px solid var(--border-soft)', background: 'transparent', color: 'var(--text-secondary)', cursor: 'pointer', fontFamily: 'var(--font-body)', fontSize: '0.85rem' }}>
                Cancel
              </button>
              <button onClick={() => { handleDelete(deleteId); setDeleteId(null); }}
                style={{ flex: 1, padding: '10px', borderRadius: 'var(--r-md)', border: 'none', background: 'var(--crimson)', color: '#fff', cursor: 'pointer', fontFamily: 'var(--font-body)', fontSize: '0.85rem', fontWeight: 700 }}>
                Delete
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════
//  TRANSACTIONS TAB — all lots, all actors
// ════════════════════════════════════════════════════════════════════════════
function TransactionsTab() {
  const { lots }  = useApp();
  const { users } = useAuth();
  const [filter, setFilter] = useState('all');
  const [search, setSearch] = useState('');
  const [siteFilter, setSiteFilter] = useState('all');

  const filtered = lots.filter(l => {
    if (filter === 'certified'  && !l.token_id)              return false;
    if (filter === 'suspect'    && l.status !== 'SUSPECT')   return false;
    if (filter === 'pending'    && (l.regulator_validated || l.status === 'SUSPECT')) return false;
    if (filter === 'delivered'  && l.transport_status !== 'delivered') return false;
    if (siteFilter !== 'all'    && l.site !== siteFilter)    return false;
    if (search && !l.lot_id.toLowerCase().includes(search.toLowerCase()) &&
        !(l.destination || '').toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });

  const SITE_COLORS = { KAMOA: '#b87333', KANSOKO: '#1a5fa0', KCC: TEAL };

  const FILTERS = [
    { id: 'all',       label: 'All lots',        count: lots.length },
    { id: 'certified', label: 'Certified (NFT)', count: lots.filter(l => l.token_id).length },
    { id: 'pending',   label: 'Awaiting DGMR',   count: lots.filter(l => !l.regulator_validated && l.status !== 'SUSPECT').length },
    { id: 'suspect',   label: 'Suspect',          count: lots.filter(l => l.status === 'SUSPECT').length },
    { id: 'delivered', label: 'Delivered',        count: lots.filter(l => l.transport_status === 'delivered').length },
  ];

  const SITES = ['all', 'KAMOA', 'KANSOKO', 'KCC'];

  const STATUS_MAP = {
    AUTHENTIQUE:  { color: TEAL,      bg: 'rgba(22,106,82,0.10)',  label: 'Authentic'  },
    SUSPECT:      { color: '#c0392b', bg: 'rgba(192,57,43,0.10)',  label: 'Suspect'    },
    'À VÉRIFIER': { color: '#b45309', bg: 'rgba(180,83,9,0.10)',   label: 'To Verify'  },
  };

  return (
    <div>
      {/* Stats row */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 12, marginBottom: 24 }}>
        <Stat label="Total Lots"   value={lots.length}                                             icon={<Ic name="package" size={16}/>}      color={TEAL}/>
        <Stat label="Certified"    value={lots.filter(l=>l.token_id).length}                       icon={<Ic name="check" size={16}/>}    color="#1a5fa0"/>
        <Stat label="In Transit"   value={lots.filter(l=>l.transport_status==='en_route').length}  icon={<Ic name="truck" size={16}/>}    color="#b87333"/>
        <Stat label="Delivered"    value={lots.filter(l=>l.transport_status==='delivered').length} icon={<Ic name="activity" size={16}/> } color="#6d3fa0"/>
      </div>

      {/* Filters */}
      <div style={{ display: 'flex', gap: 10, marginBottom: 16, flexWrap: 'wrap', alignItems: 'center' }}>
        <div style={{ display: 'flex', gap: 0, background: 'var(--bg-void)', borderRadius: 'var(--r-sm)', padding: 3, border: '1px solid var(--border-soft)' }}>
          {FILTERS.map(f => (
            <button key={f.id} onClick={() => setFilter(f.id)} style={{
              padding: '5px 11px', borderRadius: 6, border: 'none', cursor: 'pointer', whiteSpace: 'nowrap',
              background: filter === f.id ? 'var(--brand)' : 'transparent',
              color: filter === f.id ? '#fff' : 'var(--text-muted)',
              fontWeight: filter === f.id ? 700 : 500, fontSize: '0.75rem', fontFamily: 'var(--font-body)',
            }}>
              {f.label} {f.count > 0 && `(${f.count})`}
            </button>
          ))}
        </div>
        {/* Site filter */}
        <div style={{ display: 'flex', gap: 4 }}>
          {SITES.map(s => (
            <button key={s} onClick={() => setSiteFilter(s)} style={{
              padding: '5px 11px', borderRadius: 99, border: `1px solid ${siteFilter===s?SITE_COLORS[s]||TEAL:'var(--border-soft)'}`,
              background: siteFilter === s ? `${SITE_COLORS[s]||TEAL}18` : 'transparent',
              color: siteFilter === s ? SITE_COLORS[s]||TEAL : 'var(--text-muted)',
              cursor: 'pointer', fontSize: '0.72rem', fontWeight: 700, fontFamily: 'var(--font-body)',
            }}>
              {s === 'all' ? 'All Sites' : s}
            </button>
          ))}
        </div>
        <div style={{ position: 'relative', flex: 1, maxWidth: 220 }}>
          <input className="form-input" placeholder="Search lot ID…" value={search}
            onChange={e => setSearch(e.target.value)} style={{ paddingLeft: 32 }}/>
          <span style={{ position: 'absolute', left: 10, top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }}>
            <Ic size={13} d={<><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></>}/>
          </span>
        </div>
        <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginLeft: 'auto' }}>
          {filtered.length} result{filtered.length !== 1 ? 's' : ''}
        </span>
      </div>

      {/* Table */}
      <div style={{ background: 'var(--bg-raised)', borderRadius: 'var(--r-lg)', border: '1px solid var(--border-soft)', overflow: 'hidden', boxShadow: 'var(--shadow-sm)' }}>
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.82rem' }}>
            <thead>
              <tr style={{ background: 'var(--bg-void)', borderBottom: '1px solid var(--border-soft)' }}>
                {['Lot ID', 'Site', 'Mineral', 'Status', 'NFT', 'DGMR', 'Transport', 'Date'].map(h => (
                  <th key={h} style={{ padding: '10px 14px', textAlign: 'left', fontSize: '0.68rem', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.08em', color: 'var(--text-muted)', whiteSpace: 'nowrap' }}>
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.length === 0 ? (
                <tr><td colSpan={8} style={{ padding: '32px', textAlign: 'center', color: 'var(--text-muted)' }}>No transactions found</td></tr>
              ) : filtered.map((lot, i) => {
                const st  = STATUS_MAP[lot.status] || STATUS_MAP['À VÉRIFIER'];
                const sc  = SITE_COLORS[lot.site] || TEAL;
                return (
                  <tr key={lot.lot_id} style={{ borderBottom: '1px solid var(--border-dim)', background: i % 2 === 0 ? 'transparent' : 'var(--bg-void)' }}>
                    <td style={{ padding: '10px 14px' }}>
                      <span style={{ fontFamily: 'var(--font-mono)', fontSize: '0.78rem', fontWeight: 700, color: 'var(--brand)' }}>
                        {lot.lot_id}
                      </span>
                    </td>
                    <td style={{ padding: '10px 14px' }}>
                      <Pill color={sc} bg={`${sc}18`}>{lot.site}</Pill>
                    </td>
                    <td style={{ padding: '10px 14px' }}>
                      <span style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', textTransform: 'capitalize' }}>
                        {lot.mineral_type || '—'}
                      </span>
                    </td>
                    <td style={{ padding: '10px 14px' }}>
                      <Pill color={st.color} bg={st.bg}>{st.label}</Pill>
                    </td>
                    <td style={{ padding: '10px 14px' }}>
                      {lot.token_id
                        ? <span style={{ fontFamily: 'var(--font-mono)', fontSize: '0.72rem', color: '#1a5fa0', fontWeight: 700 }}>#{lot.token_id}</span>
                        : <span style={{ color: 'var(--text-muted)', fontSize: '0.72rem' }}>—</span>}
                    </td>
                    <td style={{ padding: '10px 14px' }}>
                      {lot.regulator_validated
                        ? <span style={{ color: TEAL, fontSize: '0.72rem', fontWeight: 700, display: 'flex', alignItems: 'center', gap: 4 }}><Ic name="check" size={12}/> Validated</span>
                        : lot.status === 'SUSPECT'
                          ? <span style={{ color: 'var(--crimson)', fontSize: '0.72rem', fontWeight: 700 }}>Blocked</span>
                          : <span style={{ color: '#b45309', fontSize: '0.72rem' }}>Pending</span>}
                    </td>
                    <td style={{ padding: '10px 14px' }}>
                      <span style={{ fontSize: '0.72rem', color: lot.transport_status === 'delivered' ? TEAL : lot.transport_status === 'en_route' ? '#b87333' : 'var(--text-muted)', fontWeight: lot.transport_status ? 600 : 400 }}>
                        {lot.transport_status === 'delivered' ? 'Delivered'
                          : lot.transport_status === 'en_route' ? 'In Transit'
                          : '—'}
                      </span>
                    </td>
                    <td style={{ padding: '10px 14px', color: 'var(--text-muted)', fontSize: '0.72rem', whiteSpace: 'nowrap' }}>
                      {fmt.date(lot.analyzed_at)}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

